int array_any_equal_sum(int n, int *a, int x, int y)
/*@ With l
    Require
      0 <= n &&
      Zlength(l) == n &&
      INT_MIN <= x + y && x + y <= INT_MAX &&
      IntArray::full(a, n, l)
    Ensure
      ((__return == 1 &&
        (exists i, 0 <= i && i < n && l[i] == x + y)) ||
       (__return == 0 &&
        (forall (i: Z), (0 <= i && i < n) => l[i] != x + y))) &&
      IntArray::full(a, n, l)
*/
{
